#include <bits/stdc++.h>
using namespace std;

const int N=5e4+4;

int n,k,c[N],dep[N],f[N][17],ans;
vector<int> g[N];

void dfs1(int x){
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(g[x][i]!=f[x][0]){
            int v=g[x][i];
            f[v][0]=x,dep[v]=dep[x]+1;
            for(int j=1;j<17;j++)
                f[v][j]=f[f[v][j-1]][j-1];
            dfs1(v);
        }
}

void dfs2(int x){
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(g[x][i]!=f[x][0]){
            dfs2(g[x][i]);
            c[x]+=c[g[x][i]];
        }
    ans=max(ans,c[x]);
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=16;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=16;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dep[1]=1;
    dfs1(1);
    while(k--){
        int u,v,fa;
        scanf("%d%d",&u,&v);
        fa=LCA(u,v);
        c[u]++,c[f[fa][0]]--;
        c[v]++,c[fa]--;
    }
    dfs2(1);
    printf("%d",ans);
    return 0;
}
